<template>
  <personal-score v-if="isRegistered === true" />
  <runner-register v-else-if="isRegistered === false" />
</template>

<script>
import PersonalScore from '../../components/marathon-survey/PersonalScore.vue'
import RunnerRegister from '../../components/marathon-survey/RunnerRegister.vue'

export default {
  name: 'MarathonSurveyRunnerInformation',
  components: {
    PersonalScore,
    RunnerRegister,
  },
  data () {
    return {
      isRegistered: null,
    }
  },
  created () {
    this.runnersPlaza.getRunner().then((runner) => {
      if (runner.error !== undefined) {
        this.isRegistered = false;
      } else {
        this.isRegistered = true;
      }
      console.log (runner)
      console.log (this.isRegistered)
    })
  },
}
</script>
